import styles from "./AuctionCard.module.scss";
import { useState } from "react";

export default function AuctionCard({
  title = "Honda Civic",
  description = "85.000 km rodados",
  imageUrl = "https://images.unsplash.com/photo-1617469767053-8f4f1b274d2a?w=800",
  status = "Ativo",
  onPress = () => {},
}){
  const [pressed, setPressed] = useState(false);

  return (
    <>
      <div className={styles.card_wrap}>
        <div style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
          <div
            className={styles.card}
            onClick={() => {
              setPressed(true);
              onPress?.();
              setTimeout(() => setPressed(false), 1800);
            }}
          >
            {/* Image */}
            <div className={styles.card_image}>
              <img src={imageUrl} alt={title} />
            </div>

            {/* Body */}
            <div className={styles.card_body}>
              <div className={styles.card_title}>{title}</div>

              <div className={styles.card_meta}>
                {/* Location */}
                <div className={styles.meta_row}>
                  <svg className={styles.meta_icon} viewBox="0 0 24 24" fill="none" stroke="#38bdf8" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7z"/>
                    <circle cx="12" cy="9" r="2.5"/>
                  </svg>
                  {location}
                </div>

                {/* Description */}
                <div className={styles.meta_row}>
                  <svg className={styles.meta_icon} viewBox="0 0 24 24" fill="none" stroke="#38bdf8" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <rect x="2" y="7" width="20" height="14" rx="2"/>
                    <path d="M16 7V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v2"/>
                  </svg>
                  {description}
                </div>
              </div>

              {/* Bid Box */}
              <div className={styles.bid_box}>
                <span className={styles.bid_label}>Lance Atual:</span>
                <span className={styles.bid_value}>{currentBid}</span>
              </div>
            </div>

            {/* Footer */}
            <div className={styles.card_footer}>
              <div className={styles.status_pill}>
                <span className={styles.status_dot} />
                {status}
              </div>
              <div className={styles.bids_pill}>
                <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="#64748b" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/>
                  <circle cx="9" cy="7" r="4"/>
                  <path d="M23 21v-2a4 4 0 0 0-3-3.87"/>
                  <path d="M16 3.13a4 4 0 0 1 0 7.75"/>
                </svg>
                {bids} lances
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};
